import mysql.connector
from mysql.connector import Error
import os
import getpass
import re

# MySQL Config
config = {
    'user': 'your_username',
    'password': getpass.getpass('Enter your password: '),
    'host': 'localhost',
    'database': 'your_database'
}

try:
    # Establish Connection
    conn = mysql.connector.connect(**config)
    
    if conn.is_connected():
        print('Connected to MySQL Database')
        
        # Enable Local Infile
        cursor = conn.cursor()
        cursor.execute("SET GLOBAL local_infile = 1")
        
        # Get File Path from User Input
        file_path = input("Enter the file path: ")
        
        # Validate File Path
        if not re.match(r'^[a-zA-Z0-9_\/\.]+$', file_path):
            print('Invalid file path')
            exit()
        
        # Check if File Exists
        if not os.path.isfile(file_path):
            print('File does not exist')
            exit()
        
        # Get Table Name from User Input
        table_name = input("Enter the table name: ")
        
        # Validate Table Name
        if not re.match(r'^[a-zA-Z0-9_]+$', table_name):
            print('Invalid table name')
            exit()
        
        # Execute LOAD DATA INFILE Statement
        query = "LOAD DATA INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 ROWS".format(file_path, table_name)
        cursor.execute(query)
        
        conn.commit()
        print('Data Imported Successfully')
        
except Error as e:
    print(f"Error: {e}")
finally:
    if (conn.is_connected()):
        cursor.close()
        conn.close()